package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.PrintStream;
import java.lang.reflect.Field;

import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private CSVFormat csvFormat;
    private PrintStream originalOut;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.newFormat(',');
        // Save original System.out
        originalOut = System.out;
    }

    @AfterEach
    void tearDown() {
        // Restore original System.out
        System.setOut(originalOut);
    }

    @Test
    void testPrinterNotNull() throws IOException {
        CSVPrinter printer = csvFormat.printer();
        assertNotNull(printer);
    }

    @Test
    void testPrinterUsesSystemOut() throws IOException, NoSuchFieldException, IllegalAccessException {
        // Wrap System.out to detect usage
        PrintStream spyOut = spy(System.out);
        System.setOut(spyOut);

        CSVPrinter printer = csvFormat.printer();
        assertNotNull(printer);

        // Use reflection to get the private 'out' field of CSVPrinter
        Field outField = CSVPrinter.class.getDeclaredField("out");
        outField.setAccessible(true);
        Object outObject = outField.get(printer);
        assertSame(spyOut, outObject);
    }

}
